/* аккоредон */
.accordion {border-bottom:1px solid; max-width:1000px;}
.accordion > section {}
.accordion__heading {position: relative; cursor: pointer; padding: 0px; margin: 0; color: rgba(36,36,36,1); font-weight:400; margin-bottom:-20px; display:flex; gap:10px; align-items:center;}
.accordion__heading:after, .accordion__heading:before {content: ""; position: absolute; top: 50%; right: 20px; background: rgba(36,36,36,1); transition: all 1s; width:20px; height:2px;}
.accordion__checkbox:checked~.accordion__heading:before {transform: rotate(90deg); opacity: 0; transition: all 1s;}
.accordion__heading:after {transform: rotate(90deg); transition: all 1s;}
.accordion__checkbox:checked~.accordion__heading:after {transform: rotate(180deg);}
.accordion__checkbox {display: none; position: absolute; left: -9999em;}
.accordion__checkbox:checked~.accordion__content {max-height: 1000px; transition: all 2s;}
.accordion__content {max-height: 0; overflow: hidden; padding: 0px; transition: all 0.5s; margin-bottom:20px; padding-left: 45px;}
.accordion__content > p {max-width:800px;}
.accordion h3 {color:rgba(36,36,36,1); margin-top:10px; margin-bottom:10px;}
.accordion__content > p {color:rgba(36,36,36,1); padding-top:20px;}
