<script>
(function() {
    // Настройки карты
    const imageWidth = 2560;
    const imageHeight = 1439;
    const imageUrl = 'https://obereg.club/wp-content/uploads/2026/01/2026_01_21_Obereg_cam05_pr_IB_AI_3K-scaled.jpg';
    
    // Инициализация карты с простой системой координат
    const map = L.map('<?= $bUID; ?> #map', {
        crs: L.CRS.Simple,
        minZoom: -2,
        maxZoom: 2,
        zoomControl: true,
        dragging: true,
        tap: false
    });
    
    // Вычисляем границы изображения (инвертируем Y для правильной ориентации)
    const southWest = map.unproject([0, imageHeight], 0);
    const northEast = map.unproject([imageWidth, 0], 0);
    const bounds = new L.LatLngBounds(southWest, northEast);
    
    // Добавляем изображение как подложку
    L.imageOverlay(imageUrl, bounds).addTo(map);
    map.fitBounds(bounds);
    map.setMaxBounds(bounds); // запрещаем прокрутку за пределы карты
    
    // Функция получения цвета по статусу
    function getColor(status) {
        switch(status) {
            case 'sold': return '#e74c3c';      // красный
            case 'booked': return '#f39c12';    // желтый/оранжевый
            case 'available': return '#2ecc71'; // зеленый
            case 'not-available': return '#95a5a6'; // серый
            default: return '#95a5a6';
        }
    }
    
    // Функция получения текста статуса
    function getStatusText(status) {
        switch(status) {
            case 'sold': return 'Продан';
            case 'booked': return 'Забронирован';
            case 'available': return 'Свободен';
            case 'not-available': return 'Снят с продажи';
            default: return 'Неизвестный статус';
        }
    }
    
    // Функция создания контента попапа
    function createPopupContent(data) {
        let content = `<div class="popup-content">
            <h3>${data.name}</h3>
            <span class="status ${data.status}">${getStatusText(data.status)}</span>
            <span class="place" style="color:${data.place_text_color || '#7f8c8d'}; font-style:italic; display:block; margin-bottom:10px;">
                ${data.place}
            </span>
            <div class="prop"><strong>Площадь участка:</strong> ${data.square} сот.</div>`;
        
        if (data.props && data.props.length > 0) {
            data.props.forEach(prop => {
                content += `<div class="prop"><strong>${prop.name}:</strong> ${prop.value}</div>`;
            });
        }
        
        if (data.projects && data.props.length > 0) {
            content += `<div class="prop" style="margin-top:10px;"><strong>Проект дома:</strong></div>`;
            data.projects.forEach(project => {
                content += `<div><a href="${project.link}" target="_blank" style="color:#3498db; text-decoration:none; font-weight:500;">${project.name}</a></div>`;
            });
        }
        
        if (data.specs_link) {
            content += `<div style="margin-top:15px;"><a href="${data.specs_link}" target="_blank" style="color:#3498db; text-decoration:none; font-weight:500; font-size:0.9rem;">Подробнее о комплектации</a></div>`;
        }
        
        content += `</div>`;
        return content;
    }
    
    // Массив для хранения участков
    const plots = [];
    
    // Функция добавления участка на карту
    function addPlot(data) {
        // Преобразуем координаты: инвертируем Y для системы координат карты
        const coordsMap = data.coords.map(point => {
            return [imageHeight - point[1], point[0]];
        });
        
        // Создаем многоугольник с белой рамкой 1px
        const polygon = L.polygon(coordsMap, {
            color: 'white',      // белая рамка
            weight: 1,           // толщина рамки 1px
            fillColor: getColor(data.status),
            fillOpacity: 0.75,
            plotId: data.ID
        }).addTo(map); // ← СРАЗУ ДОБАВЛЯЕМ НА КАРТУ!
        
        // Добавляем попап
        polygon.bindPopup(createPopupContent(data));
        
        // Сохраняем участок
        plots.push({
            id: data.ID,
            layer: polygon,
            status: data.status,
            data: data
        });
    }
    
    // Получаем данные об участках из настроек блока
    // Формат данных должен соответствовать: 
    // $bender_settings["genplan"] = массив объектов с полями: ID, name, place, square, status, coords (массив [x, y])
    const plotData = <?= json_encode($bender_settings["genplan"] ?? []) ?>;
    
    // Добавляем все участки на карту
    plotData.forEach(plot => {
        if (plot.coords && plot.coords.length > 0) {
            addPlot(plot);
        }
    });
    
    // Функция фильтрации участков
    function filterPlots(status) {
        plots.forEach(plot => {
            if (status === 'all' || plot.status === status) {
                if (!map.hasLayer(plot.layer)) {
                    plot.layer.addTo(map);
                }
            } else {
                if (map.hasLayer(plot.layer)) {
                    map.removeLayer(plot.layer);
                }
            }
        });
    }
    
    // Обработчики событий для кнопок фильтрации
    document.querySelectorAll('#<?= $bUID; ?> .filter-btn').forEach(button => {
        button.addEventListener('click', function() {
            // Убираем активный класс у всех кнопок
            document.querySelectorAll('#<?= $bUID; ?> .filter-btn').forEach(btn => {
                btn.classList.remove('active');
            });
            
            // Добавляем активный класс текущей кнопке
            this.classList.add('active');
            
            // Получаем статус для фильтрации
            const status = this.classList.contains('all') ? 'all' : this.classList[1];
            
            // Фильтруем участки
            filterPlots(status);
        });
    });
    
    // Отключаем скролл колесом мыши для предотвращения случайного масштабирования
    map.scrollWheelZoom.disable();
})();
</script>
